-- Import the 20 current 2026 clients/events. Safe to run more than once.
on conflict (id) do update set
 name=excluded.name,event_type=excluded.event_type,event_date=excluded.event_date,
 guests=excluded.guests,status=excluded.status,assigned_staff=excluded.assigned_staff,
 lost_reason=excluded.lost_reason,notes=excluded.notes,updated_at=now();
